INSERT INTO "dramas" ("id","title","description","cover","banner","genres","tag_list","total_episodes","rating","views","likes","review_count","average_rating","status","is_vip","is_featured","is_active","age_rating","release_date","director","cast","country","language","created_at","updated_at") VALUES('7baab2ba-1773-41d3-8cc6-4a9f700acd59', 'Hidup Kedua, Cinta Sejati Menanti', replace('Di kehidupan sebelumnya, Nadya Lestari menikah dengan Raka Wirawan, pria yang paling ia cintai. Tapi demi wanita pujaan hatinya, Raka justru menguras habis harta keluarga Nadya dan membiarkan keluarganya hancur. Takdir memberinya kesempatan kedua. Kali ini, Nadya kembali ke titik hidupnya saat harus memilih pasangan hidup. Tanpa ragu, ia memilih Dimas Pranata, pria yang tulus dan bermoral. Saat Raka sadar Nadya tak lagi memilihnya, penyesalan pun datang... tapi semuanya sudah terlambat.\n\n[BookID: 31001070612]', '\n', char(10)), 'https://stream.shortlovers.id/Hidup_Kedua,_Cinta_Sejati_Menanti/cover.jpg', 'https://stream.shortlovers.id/Hidup_Kedua,_Cinta_Sejati_Menanti/cover.jpg', '["Romance","Drama"]', '["GoodShort","Indonesian"]', 70, 0, 8019, 951, 0, false, 'completed', false, 0, 1, 'all', NULL, NULL, '[]', 'Indonesia', 'Indonesian', 1770104924, 1771644008) ON CONFLICT DO NOTHING;